25	//
26	// Cosimulation works as follows:
27	// 1. The main loop (run_cosimulation) reads and parses the next instruction
28	//    side effect from the Verilator model (piped to this process via stdin).
29	//    It stores the value in the expected_xXX global variables.
30	// 2. It then calls run_until_next_event, which calls into the emulator core to
31	//    single step until...
32	// 3. When the emulator core updates a register or performs a memory write,
33	//    it calls back into this module, one of the cosim_check_xXX functions.
34	//    The check functions compare the local side effect to the values saved
35	//    by step 1. If there is a mismatch, they flag an error, otherwise...
36	// 4. Loop back to step 1
37	//
38	
39	static void print_cosim_expected(void);
40	
41	// Returns true if the event matched, false if it did not.
42	static bool run_until_next_event(struct processor*, uint32_t thread_id);
43	
44	// Returns true if the masked values match, false otherwise
45	static bool masked_vectors_equal(uint32_t mask, const uint32_t *values1, const uint32_t *values2);
46	
47	static enum
48	{
49	    EVENT_NONE,
50	    EVENT_MEM_STORE,
51	    EVENT_VECTOR_WRITEBACK,
52	    EVENT_SCALAR_WRITEBACK
53	} expected_event;
54	static uint32_t expected_register;
55	static uint32_t expected_address;
56	static uint64_t expected_mask;
57	static uint32_t expected_values[NUM_VECTOR_LANES];
58	static uint32_t expected_pc;
59	static uint32_t expected_thread;
60	static bool cosim_mismatch;
61	static bool cosim_event_triggered;
