63	int run_cosimulation(struct processor *proc, bool verbose)
64	{
65	    char line[1024];
66	    uint32_t thread_id;
67	    uint32_t address;
68	    uint32_t pc;
69	    uint64_t write_mask;
70	    uint32_t vector_values[NUM_VECTOR_LANES];
71	    char value_str[256];
72	    uint32_t reg;
73	    uint32_t scalar_value;
74	    bool verilog_model_halted = false;
75	    size_t len;
76	
77	    enable_cosimulation(proc);
78	    if (verbose)
79	        enable_tracing(proc);
80	
81	    while (fgets(line, sizeof(line), stdin))
82	    {
83	        if (verbose)
84	            printf("%s", line);
85	
86	        len = strlen(line);
87	        if (len > 0)
88	            line[len - 1] = '\0';	// Strip off newline
89	
90	        if (sscanf(line, "store %x %x %x %" PRIx64 " %s", &pc, &thread_id, &address, &write_mask, value_str) == 5)
91	        {
92	            // Memory Store
93	            if (parse_hex_vector(value_str, vector_values, true) < 0)
94	            {
95	                printf("Error parsing cosimulation event\n");
96	                return -1;
97	            }
98	
99	            expected_event = EVENT_MEM_STORE;
100	            expected_pc = pc;
101	            expected_thread = thread_id;
102	            expected_address = address;
103	            expected_mask = write_mask;
104	            memcpy(expected_values, vector_values, sizeof(uint32_t) * NUM_VECTOR_LANES);
105	            if (!run_until_next_event(proc, thread_id))
106	                return -1;
107	        }
108	        else if (sscanf(line, "vwriteback %x %x %x %" PRIx64 " %s", &pc, &thread_id, &reg, &write_mask, value_str) == 5)
109	        {
110	            // Vector writeback
111	            if (parse_hex_vector(value_str, vector_values, false) < 0)
112	            {
113	                printf("Error parsing cosimulation event\n");
114	                return -1;
115	            }
116	
117	            expected_event = EVENT_VECTOR_WRITEBACK;
118	            expected_pc = pc;
119	            expected_thread = thread_id;
120	            expected_register = reg;
121	            expected_mask = write_mask;
122	            memcpy(expected_values, vector_values, sizeof(uint32_t) * NUM_VECTOR_LANES);
123	            if (!run_until_next_event(proc, thread_id))
124	                return -1;
125	        }
126	        else if (sscanf(line, "swriteback %x %x %x %x", &pc, &thread_id, &reg, &scalar_value) == 4)
127	        {
128	            // Scalar Writeback
129	            expected_event = EVENT_SCALAR_WRITEBACK;
130	            expected_pc = pc;
131	            expected_thread = thread_id;
132	            expected_register = reg;
133	            expected_values[0] = scalar_value;
134	            if (!run_until_next_event(proc, thread_id))
135	                return -1;
136	        }
137	        else if (strcmp(line, "***HALTED***") == 0)
138	        {
139	            verilog_model_halted = true;
140	            break;
141	        }
142	        else if (sscanf(line, "interrupt %u %x", &thread_id, &pc) == 2)
143	            cosim_interrupt(proc, thread_id, pc);
144	        else if (!verbose)
145	            printf("%s\n", line);	// Echo unrecognized lines to stdout (verbose already does this for all lines)
146	    }
147	
148	    if (!verilog_model_halted)
149	    {
150	        printf("program did not finish normally\n");
151	        printf("%s\n", line);	// Print error (if any)
152	        return -1;
153	    }
154	
155	    // Ensure emulator is also halted. If it executes any more instructions
156	    // cosim_mismatch will be flagged.
157	    cosim_event_triggered = false;
158	    expected_event = EVENT_NONE;
159	    while (!is_proc_halted(proc))
160	    {
161	        execute_instructions(proc, 1);
162	        if (cosim_mismatch)
163	            return -1;
164	    }
165	
166	    return 0;
167	}
