169	void cosim_check_set_scalar_reg(struct processor *proc, uint32_t pc, uint32_t reg, uint32_t value)
170	{
171	    cosim_event_triggered = true;
172	    if (expected_event != EVENT_SCALAR_WRITEBACK
173	            || expected_pc != pc
174	            || expected_register != reg
175	            || expected_values[0] != value)
176	    {
177	        cosim_mismatch = true;
178	        print_registers(proc, expected_thread);
179	        printf("COSIM MISMATCH, thread %u\n", expected_thread);
180	        printf("Reference: %08x s%u <= %08x\n", pc, reg, value);
181	        printf("Hardware:  ");
182	        print_cosim_expected();
183	        return;
184	    }
185	}
