187	void cosim_check_set_vector_reg(struct processor *proc, uint32_t pc, uint32_t reg, uint32_t mask,
188	                                const uint32_t *values)
189	{
190	    int lane;
191	
192	    cosim_event_triggered = true;
193	    if (expected_event != EVENT_VECTOR_WRITEBACK
194	            || expected_pc != pc
195	            || expected_register != reg
196	            || !masked_vectors_equal(mask, expected_values, values)
197	            || expected_mask != (mask & 0xffff))
198	    {
199	        cosim_mismatch = true;
200	        print_registers(proc, expected_thread);
201	        printf("COSIM MISMATCH, thread %d\n", expected_thread);
202	        printf("Reference: %08x v%u{%04x} <= ", pc, reg, mask & 0xffff);
203	        for (lane = 0; lane < NUM_VECTOR_LANES; lane++)
204	            printf("%08x ", values[lane]);
205	
206	        printf("\n");
207	        printf("Hardware:  ");
208	        print_cosim_expected();
209	        return;
210	    }
211	}
