213	void cosim_check_vector_store(struct processor *proc, uint32_t pc, uint32_t address, uint32_t mask,
214	                              const uint32_t *values)
215	{
216	    uint64_t byte_mask;
217	    int lane;
218	
219	    byte_mask = 0;
220	    for (lane = 0; lane < NUM_VECTOR_LANES; lane++)
221	    {
222	        if (mask & (1 << lane))
223	            byte_mask |= 0xf000000000000000ull >> (lane * 4);
224	    }
225	
226	    cosim_event_triggered = true;
227	    if (expected_event != EVENT_MEM_STORE
228	            || expected_pc != pc
229	            || expected_address != (address & ~(NUM_VECTOR_LANES * 4u - 1))
230	            || expected_mask != byte_mask
231	            || !masked_vectors_equal(mask, expected_values, values))
232	    {
233	        cosim_mismatch = true;
234	        print_registers(proc, expected_thread);
235	        printf("COSIM MISMATCH, thread %d\n", expected_thread);
236	        printf("Reference: %08x memory[%x]{%016" PRIx64 "} <= ", pc, address, byte_mask);
237	        for (lane = 0; lane < NUM_VECTOR_LANES; lane++)
238	            printf("%08x ", values[lane]);
239	
240	        printf("\n_hardware:  ");
241	        print_cosim_expected();
242	        return;
243	    }
244	}
