246	void cosim_check_scalar_store(struct processor *proc, uint32_t pc, uint32_t address, uint32_t size,
247	                              uint32_t value)
248	{
249	    uint32_t hardware_value;
250	    uint64_t reference_mask;
251	
252	    hardware_value = expected_values[(address & CACHE_LINE_MASK) / 4];
253	    if (size < 4)
254	    {
255	        uint32_t mask = (1 << (size * 8)) - 1;
256	        hardware_value &= mask;
257	        value &= mask;
258	    }
259	
260	    reference_mask = ((1ull << size) - 1ull) << (CACHE_LINE_MASK - (address & CACHE_LINE_MASK) - (size - 1));
261	    cosim_event_triggered = true;
262	    if (expected_event != EVENT_MEM_STORE
263	            || expected_pc != pc
264	            || expected_address != (address & ~CACHE_LINE_MASK)
265	            || expected_mask != reference_mask
266	            || hardware_value != value)
267	    {
268	        cosim_mismatch = true;
269	        print_registers(proc, expected_thread);
270	        printf("COSIM MISMATCH, thread %u\n", expected_thread);
271	        printf("Reference: %08x memory[%x]{%016" PRIx64 "} <= %08x\n", pc, address & ~CACHE_LINE_MASK,
272	               reference_mask, value);
273	        printf("Hardware:  ");
274	        print_cosim_expected();
275	        return;
276	    }
277	}
