279	static void print_cosim_expected(void)
280	{
281	    int lane;
282	
283	    printf("%08x ", expected_pc);
284	
285	    switch (expected_event)
286	    {
287	        case EVENT_NONE:
288	            printf(" HALTED\n");
289	            break;
290	
291	        case EVENT_MEM_STORE:
292	            printf("memory[%x]{%016" PRIx64 "} <= ", expected_address, expected_mask);
293	            for (lane = 0; lane < NUM_VECTOR_LANES; lane++)
294	                printf("%08x ", expected_values[lane]);
295	
296	            printf("\n");
297	            break;
298	
299	        case EVENT_VECTOR_WRITEBACK:
300	            printf("v%u{%04x} <= ", expected_register, (uint32_t)
301	                   expected_mask & 0xffff);
302	            for (lane = 0; lane < NUM_VECTOR_LANES; lane++)
303	                printf("%08x ", expected_values[lane]);
304	
305	            printf("\n");
306	            break;
307	
308	        case EVENT_SCALAR_WRITEBACK:
309	            printf("s%u <= %08x\n", expected_register, expected_values[0]);
310	            break;
311	    }
312	}
313	
314	static bool run_until_next_event(struct processor *proc, uint32_t thread_id)
315	{
316	    int count = 0;
317	
318	    cosim_mismatch = false;
319	    cosim_event_triggered = false;
320	    for (count = 0; count < 500 && !cosim_event_triggered; count++)
321	        dbg_single_step(proc, thread_id);
322	
323	    if (!cosim_event_triggered)
324	    {
325	        printf("Simulator program in infinite loop? No event occurred.  Was expecting:\n");
326	        print_cosim_expected();
327	    }
328	
329	    return cosim_event_triggered && !cosim_mismatch;
330	}
331	
332	static bool masked_vectors_equal(uint32_t mask, const uint32_t *values1, const uint32_t *values2)
333	{
334	    int lane;
335	
336	    for (lane = 0; lane < NUM_VECTOR_LANES; lane++)
337	    {
338	        if (mask & (1 << lane))
339	        {
340	            if (values1[lane] != values2[lane])
341	                return false;
342	        }
343	    }
344	
345	    return true;
346	}
